const express = require('express');
const { spawn } = require('child_process');
const app = express();

// VULNERABLE: Using child_process.exec with shell interpretation
app.get('/api/ping-vulnerable', (req, res) => {
  const { exec } = require('child_process');
  const host = req.query.host;

  exec(`ping -c 4 ${host}`, (error, stdout, stderr) => {
    if (error) {
      return res.status(500).json({ error: error.message });
    }
    res.json({ output: stdout });
  });
});

// SECURE: Using child_process.spawn with array arguments
app.get('/api/ping-secure', (req, res) => {
  const host = req.query.host;

  const ipRegex = /^(\d{1,3}\.){3}\d{1,3}$/;
  const domainRegex = /^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/;

  if (!ipRegex.test(host) && !domainRegex.test(host)) {
    return res.status(400).json({ error: 'Invalid host format' });
  }

  const pingProcess = spawn('ping', ['-c', '4', host]);

  let output = '';

  pingProcess.stdout.on('data', (data) => {
    output += data.toString();
  });

  pingProcess.on('close', (code) => {
    if (code !== 0) {
      return res.status(500).json({ error: `Ping failed with code ${code}` });
    }
    res.json({ output });
  });

  setTimeout(() => {
    pingProcess.kill();
    res.status(408).json({ error: 'Request timeout' });
  }, 10000);
});

const express = require('express');
const { spawn } = require('child_process');
const validator = require('validator');
const app = express();

const ALLOWED_COMMANDS = {
  'convert-image': {
    command: 'convert',
    formats: ['jpg', 'png', 'gif', 'webp'],
    maxSize: 10485760
  }
};

function validateCommandInput(req, res, next) {
  const { operation, filename, format } = req.body;

  if (!ALLOWED_COMMANDS[operation]) {
    return res.status(400).json({ error: 'Invalid operation' });
  }

  const filenameRegex = /^[a-zA-Z0-9_-]+$/;
  if (!filenameRegex.test(filename)) {
    return res.status(400).json({ error: 'Invalid filename format' });
  }

  if (filename.includes('..') || filename.includes('/')) {
    return res.status(400).json({ error: 'Path traversal detected' });
  }

  next();
}

const express = require('express');
const Docker = require('dockerode');
const docker = new Docker();
const app = express();

app.post('/api/execute-sandboxed', async (req, res) => {
  const { script } = req.body;

  try {
    const container = await docker.createContainer({
      Image: 'alpine:latest',
      Cmd: ['sh', '-c', script],
      HostConfig: {
        Memory: 134217728,
        NetworkMode: 'none',
        ReadonlyRootfs: true,
        SecurityOpt: ['no-new-privileges'],
        CapDrop: ['ALL'],
        PidsLimit: 50
      }
    });

    await container.start();
    const stream = await container.logs({ stdout: true, stderr: true });
    let output = '';
    stream.on('data', (chunk) => { output += chunk.toString(); });
    await container.wait();
    await container.remove();
    res.json({ output });
  } catch (error) {
    res.status(500).json({ error: 'Execution failed' });
  }
});
